+            "skip".to_string(),
+            Some(format!("Artifact not found: {artifact_rel}")),
+        );
+    };
+
+    if let Err(detail) =
+        validate_must_pass_lineage_metadata(&verdict, artifact_rel, chrono::Utc::now())
+    {
+        return ("fail".to_string(), Some(detail));
+    }
+
+    ("pass".to_string(), None)
+}
